// memetic-worker.ts — worker_threads worker for memetic SA polish.
//
// Receives a single individual's current mapping + the ciphertext +
// SA params; runs SA via solveHomophonicSubstitution(forks: 1); returns
// the polished mapping + score. The main memetic loop dispatches one
// task per individual per generation and Promise.all-s them — wall time
// drops by ~min(N_workers, population_size).
//
// HONEST SCOPE — "polish-from-fresh" semantics:
// The IDEAL worker would seed its SA from the individual's current
// mapping so polish actually improves on it. The current
// solveHomophonicSubstitution API only supports frequency-seeded or
// random-restart initial mappings — it does NOT accept a custom initial
// mapping. To work around this, the main thread passes a per-individual
// seed, but the worker still effectively runs FRESH SA each call rather
// than continuing from the individual's current state. The genetic
// crossover + elitism on the main thread carries good individuals
// forward across generations, so polish-from-fresh is acceptable
// (consistent with the sequential path's behaviour, which already does
// the same thing — see memetic-cipher-solver.ts step (b)).
//
// LOADER REQUIREMENT — tsx for TS-in-worker:
// Loaded via worker_threads from memetic-cipher-solver.ts. The Worker
// constructor MUST pass `execArgv: ['--import', 'tsx']` so this TS file
// is loadable directly in the worker process. The tsx loader is at the
// repo root's pnpm dep tree (workspace dev dep). If tsx is unavailable
// the worker will fail to start; callers should leave parallel mode off
// in that case.

import { parentPort } from 'node:worker_threads';
import { solveHomophonicSubstitution } from './homophonic-substitution-solver';

if (!parentPort) {
  throw new Error('memetic-worker: must be loaded as a worker_threads worker');
}

interface PolishTask {
  type: 'polish';
  taskId: number;
  ciphertext: string;
  // Per-task seed. The worker runs SA with this seed; the main thread
  // is responsible for streaming distinct seeds across tasks so each
  // polish run is deterministic but distinct.
  seed: number;
  saParams: {
    maxSwapsPerFork: number;
    temperatureStart?: number;
    temperatureEnd?: number;
    coolingRate?: number;
  };
}

interface PolishResult {
  type: 'done';
  taskId: number;
  mapping: Array<[string, string]>; // serializable form of Map
  score: number;
}

interface PolishError {
  type: 'error';
  taskId: number;
  error: string;
}

parentPort.on('message', (msg: PolishTask | { type: 'shutdown' }) => {
  if (msg.type === 'shutdown') {
    process.exit(0);
  }
  if (msg.type === 'polish') {
    try {
      const result = solveHomophonicSubstitution({
        ciphertext: msg.ciphertext,
        forks: 1,
        maxSwapsPerFork: msg.saParams.maxSwapsPerFork,
        stagnationLimit: 200, // unused for SA but accepted by the type
        seed: msg.seed,
        strategy: 'simulated-annealing',
        annealing: {
          temperatureStart: msg.saParams.temperatureStart,
          temperatureEnd: msg.saParams.temperatureEnd,
          coolingRate: msg.saParams.coolingRate,
        },
      });
      const out: PolishResult = {
        type: 'done',
        taskId: msg.taskId,
        mapping: [...result.mapping.entries()],
        score: result.score,
      };
      parentPort!.postMessage(out);
    } catch (err) {
      const out: PolishError = {
        type: 'error',
        taskId: msg.taskId,
        error: err instanceof Error ? err.stack ?? err.message : String(err),
      };
      parentPort!.postMessage(out);
    }
  }
});

parentPort.postMessage({ type: 'ready' });
